import React from "react";
function Consents({ prevStep, formData }) {
 return (
<div>
<h2>Consents</h2>
<p>Final Data:</p>
<pre>{JSON.stringify(formData, null, 2)}</pre>
<button onClick={prevStep}>Back</button>
<button onClick={() => alert("Submitted!")}>Submit</button>
</div>
 );
}
export default Consents;